    (N'NKT.0115', N'Lắp đặt tủ điện giám sát trạm quan trắc độ mặn tại đập ngăn mặn sông Cầu Đỏ:', N'0001', N'Đang hoạt động', NULL, N'18438', NULL, NULL, NULL, NULL, NULL, NULL, N'NKT', NULL, NULL, CONVERT(date, '2021-01-01', 23), NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, N'Lắp đặt tủ điện giám sát trạm quan trắc độ mặn tại đập ngăn mặn sông Cầu Đỏ: - Vỏ tủ điện ngoài trời, KT 800x500x300, 1 lớp cửa, sơn tĩnh điện dày 1,5mm, Kiểu treo: 01 Cái - Hệ thống năng lượng mặt trời: Tấm ắc quy năng lượng mặt trời 100Wp, bộ nạp ắc quy năng lượng mặt trời, ắc quy khô kín khí 2x35Ah: 01 Bộ - Cầu chì 5A + đế: 06 Bộ - Bộ nghịch lưu sóng Sin 50Hz: 01 Bộ - Bộ dataloger, thu thập tín hiệu Modbus RS485, truyền dữ liệu 4G, Dịch vụ lập trình thu thập hiển thị dữ liệu trên Web monitoring: 01 Bộ - Gia công giá đỡ cố định tủ điện, panel mặt trời trên cừ larsen: 01 Bộ - Đèn điện cảnh báo: 01 Bộ - Nhân công lắp đặt tủ điện, tấm panel trên thân đập và lập trình: 01 Gói', NULL, NULL, 0, 0, N'0006', N'BAN KẾ HOẠCH KỸ THUẬT', NULL, NULL, N'011', N'Ban Kế hoạch-Kỹ thuật', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
    (N'NKT.0116', N'Lắp đặt tủ quan trắc độ mặn và hệ thống điện chiếu sáng tại Đập ngăn mặn trên sông Cẩm Lệ:', N'0001', N'Đang hoạt động', NULL, N'18933', NULL, NULL, NULL, NULL, NULL, NULL, N'NKT', NULL, NULL, CONVERT(date, '2021-01-01', 23), NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, N'Lắp đặt tủ quan trắc độ mặn và hệ thống điện chiếu sáng tại Đập ngăn mặn trên sông Cẩm Lệ: - Đập ngăn mặn số 1: + Tủ cấp nguồn, chiếu sáng, quan trắc độ mặn sông Cẩm Lệ: Vỏ tủ điện ngoài trời thép không rỉ SUS304 dày 1.5mm, kiểu tủ đứng, kích thước 1400x500x400mm, Tủ gồm 02 ngăn, ngăn thiết bị điện, ngăn sensor đo mặn+đế tủ bê tông: 66.063.000 đồng + Thiết bị ngoài tủ điện: 01 Bơm ly tâm tự mồi, công suất 1HP, điện áp 220V/1pha/50Hz, Q=0.6-3m3/h, H=50-21 mét, 100m đường ống nhựa D15 kèm van khóa, 01 đèn led ngoài trời, 03 đèn cảnh báo năng lượng mặt trời, 100 mét cáp điện cấp nguồn bơm, 100 mét điện chiếu sáng, 150 mét cấp điện từ tủ công tơ, 200 mét ống luồn cáp PVC D20: 43.572.000 đồng - Đập ngăn mặn số 2: 05 bộ đèn cảnh báo chớp xoay đỏ, 01 bộ đèn led ngoài trời, 01 Timer kỹ thuật số hẹn giờ ON/OFF, 100 mét dây cáp điện, 100 ống luồn cáp PVC D20 và phụ kiện lắp đặt: 16.171.000 đồng', NULL, NULL, 0, 0, N'0006', N'BAN KẾ HOẠCH KỸ THUẬT', NULL, NULL, N'011', N'Ban Kế hoạch-Kỹ thuật', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
