    (N'NKT.0118', N'Lắp đặt vách kính, quạt hút mùi Nhà hóa chất Nhà máy nước Cầu Đỏ:', N'0001', N'Đang hoạt động', NULL, N'18590', NULL, NULL, NULL, NULL, NULL, NULL, N'NKT', NULL, NULL, CONVERT(date, '2021-01-01', 23), NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, N'Lắp đặt vách kính, quạt hút mùi Nhà hóa chất Nhà máy nước Cầu Đỏ: - Lắp đặt aptomat loại 1 pha, cường độ dòng điện <=150A: 01 Cái - Vách nhôm kính ngăn bụi: 37,215 m2 - Cửa đi bằng nhôm kính, bao gồm phụ kiện đi kèm: 1,98 m2 - Quạt hút công nghiệp KT (1060x1060x580): 01 Cái', NULL, NULL, 0, 0, N'0020', N'NMN CẦU ĐỎ', NULL, NULL, N'018', N'Nhà Máy nước Cầu Đỏ', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
    (N'NKT.0119', N'Phủ Composite 5 bể châm PAC cụm xử lý 120.000m3/ ngày tại NMN Cầu Đỏ', N'0001', N'Đang hoạt động', NULL, N'19075', NULL, NULL, NULL, NULL, NULL, NULL, N'NKT', NULL, NULL, CONVERT(date, '2021-01-01', 23), NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, N'Phủ Composite 5 bể châm PAC cụm xử lý 120.000m3/ ngày tại NMN Cầu Đỏ (HĐ số 2020/HĐKT-HPDW ngày 15/10/2020): - Phủ composite bể PAC: 204,5 m2 (200.410.000 đồng) - Phủ composite khung sắt thành bể: 20 cái (20.000.000 đồng). - Vệ sinh xử lý bề mặt bể phản ứng PAC: 204,5 m2 (17.380.000 đồng) - Vệ sinh phủ 02 lớp nhựa chống ăn mòn lưới chắn rác: 30 m2 (13.050.000 đồng)', NULL, NULL, 0, 0, N'0020', N'NMN CẦU ĐỎ', NULL, NULL, N'018', N'Nhà Máy nước Cầu Đỏ', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
