-- Converted from docs/du_lieu_daNhap.sql table QLTB_LOC.WTB_00_HO_SO_THIET_BI.
-- Imports real equipment records into dbo.ThietBi for testing.
-- Equipment group mapping uses MA_NHOM_THIET_BI child groups only; NDT_* parent groups are never assigned to ThietBi.NhomThietBiId.
SET NOCOUNT ON;

DECLARE @MaNguoiNhap NVARCHAR(50) = N'0044';
DECLARE @TenNguoiNhap NVARCHAR(250) = N'Trương Văn Voôn';

IF OBJECT_ID('tempdb..#ThietBiCu') IS NOT NULL DROP TABLE #ThietBiCu;
CREATE TABLE #ThietBiCu (
    MaThietBi NVARCHAR(50) NOT NULL, TenThietBi NVARCHAR(500) NULL, MaTrangThai NVARCHAR(50) NULL, TenTrangThai NVARCHAR(250) NULL,
    MaThietBiCha NVARCHAR(50) NULL, MaThietBiCu NVARCHAR(50) NULL, MaHieuThietBi NVARCHAR(100) NULL, MaKeToan NVARCHAR(50) NULL,
    MaNhomQuanLy NVARCHAR(50) NULL, TenNhomQuanLy NVARCHAR(250) NULL, MaNhomThietBi NVARCHAR(50) NULL, TenNhomThietBi NVARCHAR(250) NULL, KyHieuNhomThietBi NVARCHAR(20) NULL,
    MaNguoiDung NVARCHAR(50) NULL, TenNguoiDung NVARCHAR(250) NULL, NgayNhapThietBi DATE NULL, NgayDuaVaoSuDung DATE NULL,
    MaChatLieu NVARCHAR(50) NULL, TenChatLieu NVARCHAR(250) NULL, MaNuocSanXuat NVARCHAR(50) NULL, TenNuocSanXuat NVARCHAR(250) NULL,
    MaNhanHieu NVARCHAR(50) NULL, TenNhanHieu NVARCHAR(250) NULL, MaDonViCungCap NVARCHAR(50) NULL, TenDonViCungCap NVARCHAR(250) NULL,
    MaDonViTinh NVARCHAR(50) NULL, TenDonViTinh NVARCHAR(250) NULL, MaMauSac NVARCHAR(50) NULL, TenMauSac NVARCHAR(250) NULL,
    GhiChu NVARCHAR(MAX) NULL, MaNhomDoiTuong NVARCHAR(50) NULL, TenNhomDoiTuong NVARCHAR(250) NULL, ThoiGianBaoHanh INT NULL, NguyenGia DECIMAL(18,2) NULL,
    MaPhongBan NVARCHAR(50) NULL, TenPhongBan NVARCHAR(250) NULL, TrangThaiKiemKe NVARCHAR(50) NULL, TenTrangThaiKiemKe NVARCHAR(250) NULL,
    MaBoPhan NVARCHAR(50) NULL, TenBoPhan NVARCHAR(250) NULL, NgayThanhLy DATE NULL, MaLyDoThanhLy NVARCHAR(50) NULL, TenLyDoThanhLy NVARCHAR(250) NULL,
    MaLoaiThanhLy NVARCHAR(50) NULL, TenLoaiThanhLy NVARCHAR(250) NULL, NoiDungThanhLy NVARCHAR(500) NULL, MaNhomNghiepVu NVARCHAR(50) NULL, TenNhomNghiepVu NVARCHAR(250) NULL
);

IF NOT EXISTS (SELECT 1 FROM dbo.NhomThietBi WHERE MaNhomThietBi = N'KHONG_XAC_DINH')
BEGIN
    VALUES (NEWID(), N'KHONG_XAC_DINH', N'Không xác định', NULL, NULL, N'Fallback group for imported equipment without old MA_NHOM_THIET_BI.', 999999, 1, SYSDATETIME(), @MaNguoiNhap, @TenNguoiNhap);
END;

IF NOT EXISTS (SELECT 1 FROM dbo.DmDungChung WHERE NhomDanhMuc = N'TRANG_THAI_TB' AND Ma = N'KHONG_XAC_DINH')
BEGIN
    VALUES (NEWID(), N'TRANG_THAI_TB', N'KHONG_XAC_DINH', N'Không xác định', 999999, 1, SYSDATETIME(), @MaNguoiNhap, @TenNguoiNhap);
END;

;WITH NhomDoiTuong AS (
    SELECT DISTINCT N'NDT_' + MaNhomDoiTuong AS MaNhomThietBi, COALESCE(NULLIF(TenNhomDoiTuong, N''), N'Nhóm đối tượng cũ ' + MaNhomDoiTuong) AS TenNhomThietBi,
        TRY_CONVERT(INT, MaNhomDoiTuong) AS SapXep
    FROM #ThietBiCu
    WHERE MaNhomDoiTuong IS NOT NULL
)
MERGE dbo.NhomThietBi AS target
USING NhomDoiTuong AS source
ON target.MaNhomThietBi = source.MaNhomThietBi
WHEN MATCHED THEN UPDATE SET TenNhomThietBi = source.TenNhomThietBi, ParentId = NULL, IsActive = 1
WHEN NOT MATCHED THEN
    INSERT (Id, MaNhomThietBi, TenNhomThietBi, KyHieu, ParentId, MoTa, SapXep, IsActive, NgayKhoiTao, MaNguoiNhap, TenNguoiNhap)
    VALUES (NEWID(), source.MaNhomThietBi, source.TenNhomThietBi, NULL, NULL, N'Parent group converted from old MA_NHOM_DOI_TUONG in equipment data.', source.SapXep, 1, SYSDATETIME(), @MaNguoiNhap, @TenNguoiNhap);

;WITH NhomCon AS (
    SELECT MaNhomThietBi, MAX(TenNhomThietBi) AS TenNhomThietBi, MAX(KyHieuNhomThietBi) AS KyHieuNhomThietBi, MAX(MaNhomDoiTuong) AS MaNhomDoiTuong
    FROM #ThietBiCu
    WHERE MaNhomThietBi IS NOT NULL
    GROUP BY MaNhomThietBi
), NhomConSource AS (
    SELECT c.MaNhomThietBi,
        COALESCE(NULLIF(c.TenNhomThietBi, N''), N'Nhóm thiết bị cũ ' + c.MaNhomThietBi) AS TenNhomThietBi,
        c.KyHieuNhomThietBi,
        parent.Id AS ParentId
    FROM NhomCon c
    LEFT JOIN dbo.NhomThietBi parent ON parent.MaNhomThietBi = N'NDT_' + c.MaNhomDoiTuong
    WHERE c.MaNhomThietBi NOT LIKE N'NDT[_]%'
)
MERGE dbo.NhomThietBi AS target
USING NhomConSource AS source
ON target.MaNhomThietBi = source.MaNhomThietBi
WHEN MATCHED THEN UPDATE SET
    TenNhomThietBi = CASE
        WHEN target.TenNhomThietBi LIKE N'Nhóm thiết bị cũ %' AND source.TenNhomThietBi NOT LIKE N'Nhóm thiết bị cũ %' THEN source.TenNhomThietBi
        ELSE target.TenNhomThietBi
    END,
    KyHieu = COALESCE(target.KyHieu, source.KyHieuNhomThietBi),
    ParentId = COALESCE(target.ParentId, source.ParentId),
    IsActive = 1,
    NgayChinhSuaCuoiCung = SYSDATETIME(),
    MaNguoiChinhSua = @MaNguoiNhap,
    TenNguoiChinhSua = @TenNguoiNhap
WHEN NOT MATCHED THEN
    INSERT (Id, MaNhomThietBi, TenNhomThietBi, KyHieu, ParentId, MoTa, SapXep, IsActive, NgayKhoiTao, MaNguoiNhap, TenNguoiNhap)
    VALUES (NEWID(), source.MaNhomThietBi, source.TenNhomThietBi, source.KyHieuNhomThietBi, source.ParentId, N'Created from real equipment import because the group code was missing from catalog seed.', TRY_CONVERT(INT, source.MaNhomThietBi), 1, SYSDATETIME(), @MaNguoiNhap, @TenNguoiNhap);

;WITH Catalogs AS (
    SELECT N'TRANG_THAI_TB' AS NhomDanhMuc, MaTrangThai AS Ma, TenTrangThai AS Ten FROM #ThietBiCu WHERE MaTrangThai IS NOT NULL
    UNION SELECT N'TRANG_THAI_KK', TrangThaiKiemKe, TenTrangThaiKiemKe FROM #ThietBiCu WHERE TrangThaiKiemKe IS NOT NULL
    UNION SELECT N'CHAT_LIEU', MaChatLieu, TenChatLieu FROM #ThietBiCu WHERE MaChatLieu IS NOT NULL
    UNION SELECT N'NUOC_SAN_XUAT', MaNuocSanXuat, TenNuocSanXuat FROM #ThietBiCu WHERE MaNuocSanXuat IS NOT NULL
    UNION SELECT N'NHAN_HIEU', MaNhanHieu, TenNhanHieu FROM #ThietBiCu WHERE MaNhanHieu IS NOT NULL
    UNION SELECT N'DON_VI_CUNG_CAP', MaDonViCungCap, TenDonViCungCap FROM #ThietBiCu WHERE MaDonViCungCap IS NOT NULL
    UNION SELECT N'DON_VI_TINH', MaDonViTinh, TenDonViTinh FROM #ThietBiCu WHERE MaDonViTinh IS NOT NULL
    UNION SELECT N'MAU_SAC', MaMauSac, TenMauSac FROM #ThietBiCu WHERE MaMauSac IS NOT NULL
    UNION SELECT N'LY_DO_THANH_LY', MaLyDoThanhLy, TenLyDoThanhLy FROM #ThietBiCu WHERE MaLyDoThanhLy IS NOT NULL
    UNION SELECT N'LOAI_THANH_LY', MaLoaiThanhLy, TenLoaiThanhLy FROM #ThietBiCu WHERE MaLoaiThanhLy IS NOT NULL
    UNION SELECT N'NHOM_QUAN_LY', MaNhomQuanLy, TenNhomQuanLy FROM #ThietBiCu WHERE MaNhomQuanLy IS NOT NULL
    UNION SELECT N'NHOM_DOI_TUONG', MaNhomDoiTuong, TenNhomDoiTuong FROM #ThietBiCu WHERE MaNhomDoiTuong IS NOT NULL
), CatalogSource AS (
    SELECT NhomDanhMuc, Ma, COALESCE(MAX(NULLIF(Ten, N'')), Ma) AS Ten
    FROM Catalogs
    WHERE Ma IS NOT NULL
    GROUP BY NhomDanhMuc, Ma
)
MERGE dbo.DmDungChung AS target
USING CatalogSource AS source
ON target.NhomDanhMuc = source.NhomDanhMuc AND target.Ma = source.Ma
WHEN MATCHED THEN UPDATE SET Ten = source.Ten, IsActive = 1, NgayChinhSuaCuoiCung = SYSDATETIME(), MaNguoiChinhSua = @MaNguoiNhap, TenNguoiChinhSua = @TenNguoiNhap
WHEN NOT MATCHED THEN
    INSERT (Id, NhomDanhMuc, Ma, Ten, SapXep, IsActive, NgayKhoiTao, MaNguoiNhap, TenNguoiNhap)
    VALUES (NEWID(), source.NhomDanhMuc, source.Ma, source.Ten, TRY_CONVERT(INT, source.Ma), 1, SYSDATETIME(), @MaNguoiNhap, @TenNguoiNhap);

;WITH Units AS (
    SELECT MaPhongBan AS MaDonVi, TenPhongBan AS TenDonVi, N'PHONG_BAN_CU' AS LoaiDonVi FROM #ThietBiCu WHERE MaPhongBan IS NOT NULL
    UNION SELECT MaBoPhan, TenBoPhan, N'BO_PHAN' FROM #ThietBiCu WHERE MaBoPhan IS NOT NULL
), UnitSource AS (
    SELECT MaDonVi, COALESCE(MAX(NULLIF(TenDonVi, N'')), N'Đơn vị cũ ' + MaDonVi) AS TenDonVi, MAX(LoaiDonVi) AS LoaiDonVi
    FROM Units
    GROUP BY MaDonVi
)
MERGE dbo.DonViBoPhan AS target
USING UnitSource AS source
ON target.MaDonVi = source.MaDonVi
WHEN MATCHED THEN UPDATE SET TenDonVi = CASE WHEN target.LoaiDonVi = N'DON_VI_CHA_CU' THEN source.TenDonVi ELSE target.TenDonVi END, IsActive = 1
WHEN NOT MATCHED THEN
    INSERT (Id, MaDonVi, TenDonVi, ParentId, LoaiDonVi, GhiChu, SapXep, IsActive, NgayKhoiTao, MaNguoiNhap, TenNguoiNhap)
    VALUES (NEWID(), source.MaDonVi, source.TenDonVi, NULL, source.LoaiDonVi, N'Created from real equipment import.', TRY_CONVERT(INT, source.MaDonVi), 1, SYSDATETIME(), @MaNguoiNhap, @TenNguoiNhap);

;WITH Users AS (
    SELECT MaNguoiDung, MAX(TenNguoiDung) AS TenNguoiDung, MAX(MaPhongBan) AS MaPhongBan, MAX(MaBoPhan) AS MaBoPhan
    FROM #ThietBiCu
    WHERE MaNguoiDung IS NOT NULL
    GROUP BY MaNguoiDung
), UserSource AS (
    SELECT u.MaNguoiDung,
        COALESCE(NULLIF(u.TenNguoiDung, N''), N'Người sử dụng cũ ' + u.MaNguoiDung) AS TenNguoiDung,
        COALESCE(pb.Id, bp.Id) AS DonViBoPhanId
    FROM Users u
    LEFT JOIN dbo.DonViBoPhan pb ON pb.MaDonVi = u.MaPhongBan
    LEFT JOIN dbo.DonViBoPhan bp ON bp.MaDonVi = u.MaBoPhan
)
MERGE dbo.NguoiSuDungThietBi AS target
USING UserSource AS source
ON target.MaNguoiDung = source.MaNguoiDung
WHEN MATCHED THEN UPDATE SET TenNguoiDung = source.TenNguoiDung, DonViBoPhanId = COALESCE(target.DonViBoPhanId, source.DonViBoPhanId), IsActive = 1, NgayChinhSuaCuoiCung = SYSDATETIME(), MaNguoiChinhSua = @MaNguoiNhap, TenNguoiChinhSua = @TenNguoiNhap
WHEN NOT MATCHED THEN
    INSERT (Id, MaNguoiDung, TenNguoiDung, DonViBoPhanId, IsActive, NgayKhoiTao, MaNguoiNhap, TenNguoiNhap)
    VALUES (NEWID(), source.MaNguoiDung, source.TenNguoiDung, source.DonViBoPhanId, 1, SYSDATETIME(), @MaNguoiNhap, @TenNguoiNhap);

;WITH ThietBiSource AS (
    SELECT s.*,
        nhom.Id AS NhomThietBiId,
        trangThai.Id AS TrangThaiId,
        kk.Id AS TrangThaiKiemKeId,
        dvt.Id AS DonViTinhId,
        nh.Id AS NhanHieuId,
        ms.Id AS MauSacId,
        nsx.Id AS NuocSanXuatId,
        cl.Id AS ChatLieuId,
        dvcc.Id AS DonViCungCapId,
        pb.Id AS PhongBanId,
        bp.Id AS BoPhanId,
        nsd.Id AS NguoiSuDungId
    FROM #ThietBiCu s
    JOIN dbo.NhomThietBi nhom ON nhom.MaNhomThietBi = COALESCE(NULLIF(s.MaNhomThietBi, N''), N'KHONG_XAC_DINH') AND nhom.MaNhomThietBi NOT LIKE N'NDT[_]%'
    JOIN dbo.DmDungChung trangThai ON trangThai.NhomDanhMuc = N'TRANG_THAI_TB' AND trangThai.Ma = COALESCE(NULLIF(s.MaTrangThai, N''), N'KHONG_XAC_DINH')
    LEFT JOIN dbo.DmDungChung kk ON kk.NhomDanhMuc = N'TRANG_THAI_KK' AND kk.Ma = s.TrangThaiKiemKe
    LEFT JOIN dbo.DmDungChung dvt ON dvt.NhomDanhMuc = N'DON_VI_TINH' AND dvt.Ma = s.MaDonViTinh
    LEFT JOIN dbo.DmDungChung nh ON nh.NhomDanhMuc = N'NHAN_HIEU' AND nh.Ma = s.MaNhanHieu
    LEFT JOIN dbo.DmDungChung ms ON ms.NhomDanhMuc = N'MAU_SAC' AND ms.Ma = s.MaMauSac
    LEFT JOIN dbo.DmDungChung nsx ON nsx.NhomDanhMuc = N'NUOC_SAN_XUAT' AND nsx.Ma = s.MaNuocSanXuat
    LEFT JOIN dbo.DmDungChung cl ON cl.NhomDanhMuc = N'CHAT_LIEU' AND cl.Ma = s.MaChatLieu
    LEFT JOIN dbo.DmDungChung dvcc ON dvcc.NhomDanhMuc = N'DON_VI_CUNG_CAP' AND dvcc.Ma = s.MaDonViCungCap
    LEFT JOIN dbo.DonViBoPhan pb ON pb.MaDonVi = s.MaPhongBan
    LEFT JOIN dbo.DonViBoPhan bp ON bp.MaDonVi = s.MaBoPhan
    LEFT JOIN dbo.NguoiSuDungThietBi nsd ON nsd.MaNguoiDung = s.MaNguoiDung
)
MERGE dbo.ThietBi AS target
USING ThietBiSource AS source
ON target.MaThietBi = source.MaThietBi
WHEN MATCHED THEN UPDATE SET
    MaThietBiCu = source.MaThietBiCu,
    TenThietBi = COALESCE(NULLIF(source.TenThietBi, N''), source.MaThietBi),
    Model = source.MaHieuThietBi,
    MaKeToan = COALESCE(source.MaKeToan, source.MaHieuThietBi),
    MaThietBiCha = source.MaThietBiCha,
    NhomThietBiId = source.NhomThietBiId,
    TrangThaiId = source.TrangThaiId,
    TrangThaiKiemKeId = source.TrangThaiKiemKeId,
    DonViTinhId = source.DonViTinhId,
    NhanHieuId = source.NhanHieuId,
    MauSacId = source.MauSacId,
    NuocSanXuatId = source.NuocSanXuatId,
    ChatLieuId = source.ChatLieuId,
    DonViCungCapId = source.DonViCungCapId,
    PhongBanId = source.PhongBanId,
    BoPhanId = source.BoPhanId,
    NguoiSuDungId = source.NguoiSuDungId,
    NgayNhapThietBi = source.NgayNhapThietBi,
    NgayDuaVaoSuDung = source.NgayDuaVaoSuDung,
    NguyenGia = source.NguyenGia,
    ThoiGianBaoHanh = source.ThoiGianBaoHanh,
    NgayHetBaoHanh = CASE WHEN source.ThoiGianBaoHanh IS NOT NULL AND source.ThoiGianBaoHanh > 0 THEN DATEADD(MONTH, source.ThoiGianBaoHanh, COALESCE(source.NgayDuaVaoSuDung, source.NgayNhapThietBi)) ELSE NULL END,
    MaQrCode = source.MaThietBi,
    GhiChu = LEFT(source.GhiChu, 1000),
    IsActive = 1,
    NgayChinhSuaCuoiCung = SYSDATETIME(),
    MaNguoiChinhSua = @MaNguoiNhap,
    TenNguoiChinhSua = @TenNguoiNhap
WHEN NOT MATCHED THEN
    INSERT (Id, MaThietBi, MaThietBiCu, TenThietBi, Model, MaKeToan, MaThietBiCha, NhomThietBiId, TrangThaiId, TrangThaiKiemKeId, DonViTinhId, NhanHieuId, MauSacId, NuocSanXuatId, ChatLieuId, DonViCungCapId, PhongBanId, BoPhanId, NguoiSuDungId, NgayNhapThietBi, NgayDuaVaoSuDung, NguyenGia, ThoiGianBaoHanh, NgayHetBaoHanh, MaQrCode, GhiChu, IsActive, NgayKhoiTao, MaNguoiNhap, TenNguoiNhap)
    VALUES (NEWID(), source.MaThietBi, source.MaThietBiCu, COALESCE(NULLIF(source.TenThietBi, N''), source.MaThietBi), source.MaHieuThietBi, COALESCE(source.MaKeToan, source.MaHieuThietBi), source.MaThietBiCha, source.NhomThietBiId, source.TrangThaiId, source.TrangThaiKiemKeId, source.DonViTinhId, source.NhanHieuId, source.MauSacId, source.NuocSanXuatId, source.ChatLieuId, source.DonViCungCapId, source.PhongBanId, source.BoPhanId, source.NguoiSuDungId, source.NgayNhapThietBi, source.NgayDuaVaoSuDung, source.NguyenGia, source.ThoiGianBaoHanh, CASE WHEN source.ThoiGianBaoHanh IS NOT NULL AND source.ThoiGianBaoHanh > 0 THEN DATEADD(MONTH, source.ThoiGianBaoHanh, COALESCE(source.NgayDuaVaoSuDung, source.NgayNhapThietBi)) ELSE NULL END, source.MaThietBi, LEFT(source.GhiChu, 1000), 1, SYSDATETIME(), @MaNguoiNhap, @TenNguoiNhap);

DROP TABLE #ThietBiCu;
GO

-- BEGIN appended ThietBi audit fix from LOG_USER/LOG_DATE
-- Fixes ThietBi audit fields from docs/du_lieu_daNhap.sql table QLTB_LOC.WTB_00_HO_SO_THIET_BI.
-- For real equipment data, audit comes from LOG_USER/LOG_DATE/LOG_USER_LAST/LOG_DATE_LAST, not from migration user 0044.
SET NOCOUNT ON;
IF OBJECT_ID('tempdb..#ThietBiAuditCu') IS NOT NULL DROP TABLE #ThietBiAuditCu;
CREATE TABLE #ThietBiAuditCu (MaThietBi NVARCHAR(50) NOT NULL PRIMARY KEY, LogUser NVARCHAR(50) NULL, LogDate DATETIME2 NULL, LogUserLast NVARCHAR(50) NULL, LogDateLast DATETIME2 NULL);

UPDATE tb
SET
    tb.NgayKhoiTao = COALESCE(a.LogDate, tb.NgayKhoiTao),
    tb.MaNguoiNhap = COALESCE(NULLIF(a.LogUser, N''), tb.MaNguoiNhap),
    tb.TenNguoiNhap = CASE
        WHEN NULLIF(a.LogUser, N'') IS NULL THEN tb.TenNguoiNhap
        WHEN a.LogUser = N'0044' THEN N'Trương Văn Voôn'
        ELSE a.LogUser
    END,
    tb.NgayChinhSuaCuoiCung = a.LogDateLast,
    tb.MaNguoiChinhSua = NULLIF(a.LogUserLast, N''),
    tb.TenNguoiChinhSua = CASE
        WHEN NULLIF(a.LogUserLast, N'') IS NULL THEN NULL
        WHEN a.LogUserLast = N'0044' THEN N'Trương Văn Voôn'
        ELSE a.LogUserLast
    END
FROM dbo.ThietBi tb
JOIN #ThietBiAuditCu a ON a.MaThietBi = tb.MaThietBi;

DROP TABLE #ThietBiAuditCu;
GO

-- BEGIN appended NguoiSuDungThietBi audit fix from equipment LOG_USER/LOG_DATE
-- Fixes NguoiSuDungThietBi audit fields from real equipment data.
SET NOCOUNT ON;
IF OBJECT_ID('tempdb..#NguoiDungAuditCu') IS NOT NULL DROP TABLE #NguoiDungAuditCu;
CREATE TABLE #NguoiDungAuditCu (MaNguoiDung NVARCHAR(50) NOT NULL PRIMARY KEY, LogUser NVARCHAR(50) NULL, LogDate DATETIME2 NULL, LogUserLast NVARCHAR(50) NULL, LogDateLast DATETIME2 NULL);

UPDATE nsd
SET
    nsd.NgayKhoiTao = COALESCE(a.LogDate, nsd.NgayKhoiTao),
    nsd.MaNguoiNhap = COALESCE(NULLIF(a.LogUser, N''), nsd.MaNguoiNhap),
    nsd.TenNguoiNhap = CASE
        WHEN NULLIF(a.LogUser, N'') IS NULL THEN nsd.TenNguoiNhap
        WHEN a.LogUser = N'0044' THEN N'Trương Văn Voôn'
        ELSE a.LogUser
    END,
    nsd.NgayChinhSuaCuoiCung = a.LogDateLast,
    nsd.MaNguoiChinhSua = NULLIF(a.LogUserLast, N''),
    nsd.TenNguoiChinhSua = CASE
        WHEN NULLIF(a.LogUserLast, N'') IS NULL THEN NULL
        WHEN a.LogUserLast = N'0044' THEN N'Trương Văn Voôn'
        ELSE a.LogUserLast
    END
FROM dbo.NguoiSuDungThietBi nsd
JOIN #NguoiDungAuditCu a ON a.MaNguoiDung = nsd.MaNguoiDung;

DROP TABLE #NguoiDungAuditCu;
GO
